  static List<String> get stateNames => states.keys.toList()..sort();

  static List<String> getLGAs(String state) {
    final data = states[state];
    if (data == null) return [];
    return List<String>.from(data['lgas'] as List);
  }

  static double getLatitude(String state) {
    return (states[state]?['lat'] ?? 0.0).toDouble();
  }

  static double getLongitude(String state) {
    return (states[state]?['lng'] ?? 0.0).toDouble();
  }

  // Find the closest Nigerian state to the given coordinates
  static String reverseGeocode(double lat, double lng) {
    String closest = 'Unknown';
    double minDist = double.infinity;

    for (final entry in states.entries) {
      final sLat = (entry.value['lat'] as num).toDouble();
      final sLng = (entry.value['lng'] as num).toDouble();
      final dist = (sLat - lat) * (sLat - lat) + (sLng - lng) * (sLng - lng);
      if (dist < minDist) {
        minDist = dist;
        closest = entry.key;
      }
    }

    return '$closest State';
  }
}
